<template><ModulePageShell title="质控缺陷闭环" description="缺陷独立整改、复核和关闭，不修改临床源记录"><template #chips><a-tag color="red">缺陷 {{ defects.length }}</a-tag><a-tag>病例 {{ cases.length }}</a-tag></template><template #toolbar><a-button :loading="loading" @click="reload">刷新</a-button></template><a-alert v-if="error" type="error" show-icon>{{error}}</a-alert><a-card class="section-card" :bordered="false" title="真实质控病例穿透"><a-empty v-if="!loading&&!cases.length" description="当前筛选没有真实质控病例"/><a-table v-else :data="cases" row-key="operationId" :pagination="false"><a-table-column title="病例ID" data-index="operationId"/><a-table-column title="患者" data-index="operationCase.patientName"/><a-table-column title="手术" data-index="operationCase.operationName"/><a-table-column title="风险" data-index="riskLevel"/><a-table-column title="异常指标"><template #cell="{record}">{{defectIndicatorCount(record)}}</template></a-table-column><a-table-column title="操作"><template #cell="{record}"><a-link @click="goCaseDetail(record.operationId)">穿透病例</a-link></template></a-table-column></a-table></a-card><a-card class="section-card" :bordered="false" title="缺陷列表"><a-empty v-if="!loading&&!defects.length" description="暂无质控缺陷"/><a-table v-else :data="defects" row-key="defectId" :pagination="false"><a-table-column title="病例ID" data-index="operationId"/><a-table-column title="指标" data-index="indicatorCode"/><a-table-column title="来源"><template #cell="{record}">{{record.sourceModule||'—'}} / {{record.sourceRecordId||'—'}}</template></a-table-column><a-table-column title="等级" data-index="severity"/><a-table-column title="说明" data-index="description"/><a-table-column title="版本"><template #cell="{record}">v{{record.version}}</template></a-table-column><a-table-column title="状态" data-index="status"/><a-table-column title="操作" :width="220"><template #cell="{record}"><a-space><a-link @click="goCaseDetail(record.operationId)">穿透</a-link><a-link v-if="record.status==='open'&&can('quality.defect.rectify')" @click="openAction(record,'rectify')">提交整改</a-link><a-link v-if="record.status==='rectifying'&&can('quality.defect.review')" @click="openAction(record,'review')">复核</a-link><a-link v-if="record.status==='resolved'&&can('quality.defect.close')" @click="openAction(record,'close')">关闭</a-link></a-space></template></a-table-column></a-table></a-card><a-modal v-model:visible="actionVisible" :title="actionTitle" :ok-loading="saving" @ok="submitAction"><a-form :model="actionForm" layout="vertical"><a-form-item :label="actionKind==='rectify'?'整改方案':actionKind==='review'?'复核意见':'关闭原因'" required><a-textarea v-model="actionText" :auto-size="{minRows:3}"/></a-form-item><a-form-item v-if="actionKind==='review'" label="复核结论"><a-radio-group v-model="approved"><a-radio :value="true">通过</a-radio><a-radio :value="false">退回整改</a-radio></a-radio-group></a-form-item></a-form></a-modal></ModulePageShell></template>
<script setup lang="ts">import{computed,onMounted,ref}from'vue';import{Message}from'@arco-design/web-vue';import{useRouter}from'vue-router';import ModulePageShell from'@/components/shared/ModulePageShell.vue';import{authApi}from'@/api/auth';import type{DefectRecordApi,QualityDrilldownCaseApi}from'@/api/quality';import{closeQualityDefect,loadQualityCases,loadQualityDefects,reviewQualityDefect,submitQualityRectification}from'@/services/anesthesia/qualityCaseService';
const router=useRouter(),cases=ref<QualityDrilldownCaseApi[]>([]),defects=ref<DefectRecordApi[]>([]),permissions=ref<string[]>([]),loading=ref(false),saving=ref(false),error=ref('');const actionVisible=ref(false),actionKind=ref<'rectify'|'review'|'close'>('rectify'),actionText=ref(''),approved=ref(true),selected=ref<DefectRecordApi|null>(null);const actionForm=computed(()=>({text:actionText.value,approved:approved.value}));const actionTitle=computed(()=>({rectify:'提交整改方案',review:'复核整改结果',close:'关闭质控缺陷'}[actionKind.value]));const can=(code:string)=>permissions.value.some(v=>v==='*'||v==='quality.*'||v===code);
async function reload(){loading.value=true;error.value='';try{const[c,d]=await Promise.all([loadQualityCases({page:1,pageSize:100}),loadQualityDefects({page:1,pageSize:100})]);cases.value=c.list;defects.value=d.list;}catch(e){cases.value=[];defects.value=[];error.value=`加载失败：${(e as Error).message}`;}finally{loading.value=false;}}
function openAction(record:DefectRecordApi,kind:'rectify'|'review'|'close'){selected.value=record;actionKind.value=kind;actionText.value='';approved.value=true;actionVisible.value=true;}
async function submitAction(){const record=selected.value;if(!record||!actionText.value.trim()){Message.warning('请填写原因或意见');return;}saving.value=true;try{if(actionKind.value==='rectify')await submitQualityRectification({defectId:record.defectId,expectedVersion:record.version,rectification:actionText.value.trim()});else if(actionKind.value==='review')await reviewQualityDefect({defectId:record.defectId,expectedVersion:record.version,approved:approved.value,reviewOpinion:actionText.value.trim()});else await closeQualityDefect({defectId:record.defectId,expectedVersion:record.version,reason:actionText.value.trim()});actionVisible.value=false;await reload();Message.success('状态已保存并回读');}catch(e){Message.error((e as Error).message);}finally{saving.value=false;}}
const defectIndicatorCount=(r:QualityDrilldownCaseApi)=>r.indicatorResults.filter(x=>x.status==='fail'||x.status==='warn').length;const goCaseDetail=(id:string)=>router.push({name:'record',params:{id},query:{from:'quality'}});async function loadPermissions(){try{const r=await authApi.myPermissions();permissions.value=Array.isArray(r?.permissions)?r.permissions.map(String):[];}catch{permissions.value=[];}}onMounted(()=>Promise.all([loadPermissions(),reload()]));
</script>
